from typing import List

def solve(nums: List[int]) -> int:
    ones = []
    twos = []
    for i, num in enumerate(nums):
        if num == 1:
            ones.append(i)
        elif num == 2:
            twos.append(i)
    min_diff = float('inf')
    for i in ones:
        for j in twos:
            diff = abs(i - j)
            if diff < min_diff:
                min_diff = diff
    return min_diff if min_diff != float('inf') else -1
